// Solution goes here
function calculateExchangeRate(exchangeRates, targetCurrency) {
  let baseCurrency = "USD";
  let targetRate = exchangeRates[exchangeRates.length - 1][1];
  for (let i = 0; i < exchangeRates.length; i++) {
    if (exchangeRates[i][0] === baseCurrency) {
      let exchangeRate = targetRate / exchangeRates[i][1];
      return exchangeRate;
    }
  }
  return 0;
}
